INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06390', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於校園的霸凌事件，下列敘述何者正確？ 校園霸凌指同校學生與學生間，與校園內、外所發生之霸凌行為 各級學校應成立常設性防治校園霸凌小組，由輔導主任擔任召集人 根據兒童福利聯盟對4980位國小到高中職在學學生調查（2014），校園霸凌以關係霸凌最多、言語霸 凌次之 校園霸凌行為如果已經達到身心虐待的程度，校長及老師應依法通報', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06391', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於收/出養子女，下列敘述何者正確？ 夫妻共同收養時，雙方的年齡都必須比被收養人大二十歲以上 近親之間的收養只要雙方同意，就可以去戶政事務所辦理收養戶籍登記 原住民被非原住民收養，其原住民身分隨即喪失 我國法律對單身收養並無特別規定', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06392', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於思覺失調症（原稱精神分裂症）的預後，下列敘述何者正確？ 突然發作者比不知不覺中慢慢發作的預後較好 15歲之前發作比30歲之後發作預後較好 女性患者的預後比男性患者好 沒有親戚朋友的患者預後較好', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 21, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06393', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於兒童少年保護制度，下列敘述何者正確？ 高風險家庭服務係指經家防中心調查，兒少受虐情節輕微，但仍需引進福利資源，持續監督一段時間 的服務 依兒童及少年福利與權益保障法，兒少保護個案緊急安置48小時仍不足以保護兒少時，須向法院聲請 繼續安置，以3個月為限 父母、監護人、或其他實際照顧兒童少年之人，經主管機關依兒童及少年福利與權益保障法相關條文 處罰，情節嚴重者，應接受6小時以上，50小時以下之親職教育輔導 直轄市、縣（市）主管機關於知悉或接獲有應保護之兒童少年通報時，應視需要立即指派社政、衛 政、教育或警政單位等處理，至遲不得超過二十四小時', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06394', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於同志之間的親密暴力事件，下列敘述何者正確？ 曾有或現有同居關係的伴侶已經在2007年被納入「家庭暴力防治法」的保護範圍 同志伴侶沒有婚姻關係，遭受暴力之後，比較容易離開 同志遭受暴力向外求助，等於出櫃 同志伴侶間的暴力行為與異性戀者的不同', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06395', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於柯伯格（Kohlberg）的道德發展階段論，下列陳述何者正確？ 道德發展共分7個階段   階段2：公平為上 階段4：與他人一樣    階段6：有原則的良知', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06396', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於藥物濫用問題，以下敘述何者正確？ 家庭或社區對藥物濫用的接納度是影響青少年濫用的重要原因 青少年使用海洛英是相當普遍的現象 臺灣目前以美沙酮（東）替代療法幫助海洛英毒癮者戒毒 藥物濫用是個人意志力的問題，不是精神疾病', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06397', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於老年階段的身心變化現象，以下敘述何者正確？ 心跳增加  動脈硬化增加  骨質密度增加  嗅覺敏感度增加', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06398', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於大陸配偶，以下敘述何者正確？ 依親居留滿6年，每年居住逾183日，得申請長期居留 長期居留連續滿3年，即可申請定居，領取身分證 依親居留期間，可以工作，但需先申請工作證 長期居留期間，可以繼承不動產，但如為臺灣地區繼承人賴以居住的不動產，大陸配偶不得繼承', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06399', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者不是酷兒〈Queer〉多元性的類型？ 女性主義者  同性戀  雙性戀  跨性別者', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "fd4985eec327", "answer_pdf_sha1": "0c1017521c34", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
